import { HttpModule } from '@nestjs/axios';
import { Module } from '@nestjs/common';
import { BullModule } from '@nestjs/bullmq';

import { CacheModule } from '@modules/cache/cache.module';
import { DbModule } from '@modules/db/db.module';
import { EnvConfigModule } from '@modules/env-config/env-config.module';
import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
import { GithubRepoModel } from '@modules/github/db/github-repos.model';
import { GithubAppService } from '@modules/github/github-app.service';
import { GithubInstallController } from '@modules/github/github-install.controller';
import { GithubInstallService } from '@modules/github/github-install.service';
import { GithubWebhookController } from '@modules/github/github-webhook.controller';
import { GithubWebhookService } from '@modules/github/github-webhook.service';

@Module({
  imports: [
    HttpModule,
    CacheModule,
    DbModule,
    EnvConfigModule,
    BullModule.registerQueue({ name: 'github' }),
  ],
  controllers: [GithubInstallController, GithubWebhookController],
  providers: [
    GithubInstallationModel,
    GithubRepoModel,
    GithubAppService,
    GithubInstallService,
    GithubWebhookService,
  ],
  exports: [GithubAppService],
})
export class GithubModule {}
```

