14	@Injectable()
15	export class GithubWebhookService {
16		private readonly logger = new Logger(GithubWebhookService.name);
17	
18		constructor(
19			private readonly configService: EnvConfigService,
20			private readonly githubInstallationModel: GithubInstallationModel,
21			@InjectQueue('github') private readonly githubQueue: Queue,
22		) {}
23	
24		verifySignature({
25			payload,
26			signature,
27		}: {
28			payload: string;
29			signature: string;
30		}): boolean {
31			const secret = this.configService.get<string>({ key: GITHUB_APP_WEBHOOK_SECRET });
32			const computed = `sha256=${createHmac('sha256', secret).update(payload).digest('hex')}`;
33	
34			const trusted = Buffer.from(signature);
35			const untrusted = Buffer.from(computed);
36	
37			if (trusted.length !== untrusted.length) return false;
38			return timingSafeEqual(trusted, untrusted);
39		}
40	
41		async handleEvent({
42			event,
43			installationId,
44			payload,
45		}: {
46			event: string;
47			installationId: number;
48			payload: unknown;
49		}): Promise<void> {
50			const installation = await this.githubInstallationModel.findByInstallationId({
51				installationId,
52			});
53	
54			if (!installation) {
55				this.logger.warn(`Webhook received for unknown installation: ${installationId}`);
56				return;
57			}
58	
59			if (installation.status === GithubInstallationStatus.UNINSTALLED) {
60				this.logger.warn(`Webhook received for uninstalled installation: ${installationId}`);
61				return;
62			}
63	
64			if (event === 'installation') {
65				await this.handleInstallationLifecycle({
66					installationId,
67					payload: payload as IGithubInstallationEvent,
68				});
69				return;
70			}
71	
72			if (installation.status === GithubInstallationStatus.SUSPENDED) {
73				this.logger.warn(`Dropping event for suspended installation: ${installationId}`);
74				return;
75			}
76	
77			await this.githubQueue.add('raw_event', {
78				event,
79				installationId,
80				payload,
81				receivedAt: new Date(),
82			});
83	
84			this.logger.debug(`Queued ${event} event for installation ${installationId}`);
85		}
86	
87		private async handleInstallationLifecycle({
88			installationId,
89			payload,
90		}: {
91			installationId: number;
92			payload: IGithubInstallationEvent;
93		}): Promise<void> {
94			if (payload.action === 'deleted') {
95				await this.githubInstallationModel.markUninstalled({ installationId });
96				this.logger.debug(`Installation ${installationId} uninstalled`);
97			} else if (payload.action === 'suspend') {
98				await this.githubInstallationModel.markSuspended({ installationId });
99				this.logger.debug(`Installation ${installationId} suspended`);
100			} else if (payload.action === 'unsuspend') {
101				await this.githubInstallationModel.markActive({ installationId });
102				this.logger.debug(`Installation ${installationId} unsuspended`);
103			}
104		}
105	}
