30		generateAppJwt(): string {
31			const appId = this.configService.get<string>({ key: GITHUB_APP_ID });
32			const rawKey = this.configService.get<string>({ key: GITHUB_APP_PRIVATE_KEY });
33			const privateKey = rawKey.replace(/\\n/g, '\n');
34	
35			const now = Math.floor(Date.now() / 1000);
36			const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString(
37				'base64url',
38			);
39			const payload = Buffer.from(
40				JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId }),
41			).toString('base64url');
42			const data = `${header}.${payload}`;
43	
44			const sign = createSign('RSA-SHA256');
45			sign.update(data);
46			const signature = sign.sign(privateKey, 'base64url');
47	
48			return `${data}.${signature}`;
49		}
50	
51		async getInstallationToken({ installationId }: { installationId: number }): Promise<string> {
52			const cached = await this.cacheService.get<string>({
53				namespace: Namespaces.GITHUB_TOKEN,
54				key: String(installationId),
55				consistencyLevel: ConsistencyLevel.STRONG,
56			});
57	
58			if (cached) {
59				return cached;
60			}
61	
62			const jwt = this.generateAppJwt();
63			const { data } = await this.httpService.axiosRef.post<IGithubApiInstallationToken>(
64				`https://api.github.com/app/installations/${installationId}/access_tokens`,
65				{},
66				{
67					headers: {
68						Authorization: `Bearer ${jwt}`,
69						Accept: 'application/vnd.github+json',
70						'X-GitHub-Api-Version': '2022-11-28',
71					},
72				},
73			);
74	
75			await this.cacheService.set({
76				namespace: Namespaces.GITHUB_TOKEN,
77				key: String(installationId),
78				value: data.token,
79				ttl: GITHUB_TOKEN_TTL_MS,
80			});
81	
82			this.logger.debug(`Generated installation token for installation ${installationId}`);
83			return data.token;
84		}
