17		JWT_SECRET: 'test-secret-key-that-is-at-least-32-characters-long',
18		JWT_ACCESS_TOKEN_EXPIRY: '900',
19		JWT_REFRESH_TOKEN_EXPIRY_DAYS: '30',
20		GITHUB_CLIENT_ID: 'github-client-id',
21		GITHUB_CLIENT_SECRET: 'github-client-secret',
22		GITHUB_CALLBACK_URL: 'http://localhost:3001/api/auth/github/callback',
