24		GOOGLE_CLIENT_SECRET: 'google-client-secret',
25		GOOGLE_CALLBACK_URL: 'http://localhost:3001/api/auth/google/callback',
26		FRONTEND_URL: 'http://localhost:3000',
27		ENCRYPTION_KEY: 'a'.repeat(64),
28	};
29	
30	describe('env-validations.config', () => {
31		describe('validate', () => {
32			let loggerErrorSpy: jest.SpyInstance;
33	
34			beforeEach(() => {
35				loggerErrorSpy = jest.spyOn(Logger, 'error').mockImplementation(jest.fn());
36			});
37	
38			afterEach(() => {
39				jest.clearAllMocks();
40			});
41	
42			it('should return validated config for valid input', () => {
43				const result = validate({ envConfig: validEnvConfig });
44	
45				expect(result).toBeDefined();
46				expect(result.NODE_ENV).toBe('test');
47				expect(result.PORT).toBe(3001);
48				expect(result.GLOBAL_PREFIX).toBe('api');
49				expect(result.SERVER_NAME).toBe('webapp-backend-test');
50				expect(typeof result.IS_COMPACT_LOGS).toBe('boolean');
51				expect(typeof result.IS_JSON_LIKE_LOGS).toBe('boolean');
52				expect(result.GRACEFUL_SHUTDOWN_DELAY).toBe(0);
53			});
54	
55			it('should throw when NODE_ENV is invalid enum value', () => {
56				expect(() =>
57					validate({ envConfig: { ...validEnvConfig, NODE_ENV: 'invalid' } }),
58				).toThrow();
59				expect(loggerErrorSpy).toHaveBeenCalledWith(
60					'Config validation error',
61					expect.any(Array),
62				);
63			});
64	
65			it('should throw when PORT is out of range', () => {
66				expect(() =>
67					validate({ envConfig: { ...validEnvConfig, PORT: '99999' } }),
68				).toThrow();
69			});
70	
71			it('should throw when GRACEFUL_SHUTDOWN_DELAY exceeds max', () => {
72				expect(() =>
73					validate({ envConfig: { ...validEnvConfig, GRACEFUL_SHUTDOWN_DELAY: '99999' } }),
74				).toThrow();
75			});
76	
77			it('should throw when required string field is empty', () => {
78				expect(() =>
79					validate({ envConfig: { ...validEnvConfig, GLOBAL_PREFIX: '' } }),
80				).toThrow();
81			});
82	
83			it('should throw when required field is missing', () => {
84				const { PORT: _port, ...missingPort } = validEnvConfig;
85				expect(() => validate({ envConfig: missingPort })).toThrow();
86			});
87		});
88	});
